import{_ as o,o as t,c as a,ao as i}from"./chunks/framework.pOvm8ivT.js";const s="/EDUC_BiDiM_IRM/previews/PR7/assets/logo_UB.9dpmOVWY.png",r="/EDUC_BiDiM_IRM/previews/PR7/assets/LOGO_CNRS_BLEU.COFav-FC.png",n="/EDUC_BiDiM_IRM/previews/PR7/assets/logo_rmsb.C3gkxT7r.png",f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),l={name:"index.md"};function u(p,e,c,h,d,m){return t(),a("div",null,[...e[0]||(e[0]=[i('<div style="display:flex;justify-content:center;gap:20px;align-items:center;"><img src="'+s+'" alt="Logo UB" width="250"><img src="'+r+'" alt="Logo CNRS" width="100"><img src="'+n+'" alt="Logo CRMSB" width="100"></div><div style="text-align:center;"><p style="font-weight:bold;font-size:35px;font-variant:small-caps;margin:0px;"> Master 2 : Biomedical MRI course </p></div><p>Welcome to the <em>Master 2 : Biomedical MRI</em> course offered by Aurélien Trotier at university of Bordeaux</p><h2 id="Goals" tabindex="-1">Goals <a class="header-anchor" href="#Goals" aria-label="Permalink to &quot;Goals {#Goals}&quot;">​</a></h2><p>The goal of this website is to give you an advanced formation about MRI physics, pulse sequence development and reconstruction focused on reusable technical skills.</p><p>Lectures will be done by Professors and this website will be used to teach complementary and more specific knowledges about MRI topics.</p><p>After taking this class, you should be able to start your internship with a broad knowledge about MRI and associated coding skills that will make your life (as well as your supervisor) easier.</p><h2 id="Prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#Prerequisites" aria-label="Permalink to &quot;Prerequisites {#Prerequisites}&quot;">​</a></h2><p>No knowledge of the Julia programming language is required: this course only assumes knowledge of common programming concepts like for-loops and arrays.</p><h2 id="Contents" tabindex="-1">Contents <a class="header-anchor" href="#Contents" aria-label="Permalink to &quot;Contents {#Contents}&quot;">​</a></h2><h3 id="Lectures" tabindex="-1">Lectures <a class="header-anchor" href="#Lectures" aria-label="Permalink to &quot;Lectures {#Lectures}&quot;">​</a></h3><p>The course is taught in 4 months and are seperated in Teaching Units (UE) :</p><ul><li><p>UE Technologie de l’IRM &amp; Reconstruction d’images</p></li><li><p>UE Mathématiques, Programmation (avancée) pour l’imagerie &amp; Traitement/analyse d’image</p></li><li><p>UE Instrumentation et dispositifs biomédicaux pour l’IRM</p></li><li><p>UE Physiologie, physiopathologie et Imagerie des grandes fonctions physiologiques</p></li></ul><p>Most of the topics of this website will cover the first 2 UE.</p><h2 id="FAQ" tabindex="-1">FAQ <a class="header-anchor" href="#FAQ" aria-label="Permalink to &quot;FAQ {#FAQ}&quot;">​</a></h2><h4 id="Why-should-I-learn-Julia?" tabindex="-1">Why should I learn Julia? <a class="header-anchor" href="#Why-should-I-learn-Julia?" aria-label="Permalink to &quot;Why should I learn Julia? {#Why-should-I-learn-Julia?}&quot;">​</a></h4><p>Paraphrasing the <a href="https://julialang.org" target="_blank" rel="noreferrer">official website</a>, Julia is:</p><ul><li><p><strong>Fast:</strong> designed for high performance computing, compiles to LLVM</p></li><li><p><strong>Dynamic:</strong> dynamically typed, interactive REPL</p></li><li><p><strong>Reproducible:</strong> great package manager, reproducible environments and pre-built binaries</p></li><li><p><strong>Composable:</strong> uses multiple dispatch</p></li><li><p><strong>General:</strong> allows async I/O, metaprogramming, etc.</p></li><li><p><strong>Open source:</strong> open development, uses permissive MIT license</p></li></ul><p>If these are features that sound appealing to you, you should learn Julia!</p><h4 id="How-can-I-run-the-notebooks?" tabindex="-1">How can I run the notebooks? <a class="header-anchor" href="#How-can-I-run-the-notebooks?" aria-label="Permalink to &quot;How can I run the notebooks? {#How-can-I-run-the-notebooks?}&quot;">​</a></h4><p>Running notebooks is described in the next section of the <em>Installation</em> notebook.</p><p>Alternatively, you can open the notebook on Binder by clicking <em>&quot;Edit or run this notebook&quot;</em>. However, Binder can take a prohibitively long time to load. Pluto notebooks show an estimate of the loading times above the <em>&quot;Run in Binder&quot;</em> button.</p><p>If you are familiar with Git, you can also clone the <a href="https://github.com/CRMSB/EDUC_BiDiM_IRM" target="_blank" rel="noreferrer">GitHub repository of this course</a>. You can then open your local copy of the lectures and homework in Pluto. Just make sure to regularly pull to keep your copy of the course up to date.</p><h2 id="Acknowledgements" tabindex="-1">Acknowledgements <a class="header-anchor" href="#Acknowledgements" aria-label="Permalink to &quot;Acknowledgements {#Acknowledgements}&quot;">​</a></h2><p>The format of this website as well as the contents of this course are influenced by the following lectures:</p><ul><li><a href="https://adrianhill.de/julia-ml-course/" target="_blank" rel="noreferrer"><em>Julia for Machine Learning</em></a> at TU Berlin by Prof. Klaus-Robert Müller</li></ul>',26)])])}const b=o(l,[["render",u]]);export{f as __pageData,b as default};
